import{_ as a,o as t,c as r,a1 as i}from"./chunks/framework.BwhMLafE.js";const u=JSON.parse('{"title":"Core Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),n={name:"architecture.md"};function o(s,e,l,c,d,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="core-architecture" tabindex="-1">Core Architecture <a class="header-anchor" href="#core-architecture" aria-label="Permalink to &quot;Core Architecture&quot;">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#overview">Overview</a></li><li><a href="#unified-no-lexer-design">Unified No-Lexer Design</a></li><li><a href="#native-call-stack-execution">Native Call-Stack Execution</a></li><li><a href="#dynamic-stack-overflow-recovery">Dynamic Stack-Overflow Recovery</a></li><li><a href="#dense-integer-node-pooling">Dense Integer Node Pooling</a></li><li><a href="#role-of-the-python-generator">Role of the Python Generator</a></li><li><a href="#self-hosting-roadmap">Self-Hosting Roadmap</a></li></ul><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Galley achieves parsing speeds tens to hundreds of times faster than traditional table-driven parser generators by fundamentally rethinking how parsers interact with memory and the CPU. Rather than interpreting state transitions at runtime, Galley directly encodes grammar semantics into compile-time Zig execution paths.</p><hr><h2 id="unified-no-lexer-design" tabindex="-1">Unified No-Lexer Design <a class="header-anchor" href="#unified-no-lexer-design" aria-label="Permalink to &quot;Unified No-Lexer Design&quot;">​</a></h2><p>Traditional parsers split execution into two passes: a lexer (tokenizer) that scans source text and allocates token objects on the heap, followed by a parser that consumes those tokens.</p><p>Galley eliminates the separate lexer pass entirely. Character matching and structural grammar reduction happen simultaneously in a single, unified pass over the source byte buffer. By avoiding token allocation and intermediate buffering, memory bus traffic is reduced by over 50%.</p><hr><h2 id="native-call-stack-execution" tabindex="-1">Native Call-Stack Execution <a class="header-anchor" href="#native-call-stack-execution" aria-label="Permalink to &quot;Native Call-Stack Execution&quot;">​</a></h2><p>In both generated LL recursive-descent and LR recursive-ascent parsers, Galley leverages the native CPU execution call stack as the grammar parsing stack.</p><p>Instead of dynamically allocating stack frame objects or pushing/popping state IDs in an array loop, grammar transitions compile directly into native machine function calls (<code>call</code> and <code>ret</code> instructions). This allows modern CPUs to fully utilize their hardware return address stacks (RAS) and branch prediction units, resulting in near-zero overhead state transitions.</p><hr><h2 id="dynamic-stack-overflow-recovery" tabindex="-1">Dynamic Stack-Overflow Recovery <a class="header-anchor" href="#dynamic-stack-overflow-recovery" aria-label="Permalink to &quot;Dynamic Stack-Overflow Recovery&quot;">​</a></h2><p>Leveraging the native CPU call stack introduces a potential risk when parsing deeply recursive structures (such as thousands of nested JSON arrays): exceeding the operating system thread stack limit.</p><p>To prevent crashes, Galley includes a runtime stack-overflow recovery mechanism. As parsing approaches the stack limit, the runtime intercepts execution and dynamically transitions to heap-backed continuation frames. This guarantees safety on arbitrarily deep input files while maintaining maximum bare-metal speed during normal execution depths.</p><hr><h2 id="dense-integer-node-pooling" tabindex="-1">Dense Integer Node Pooling <a class="header-anchor" href="#dense-integer-node-pooling" aria-label="Permalink to &quot;Dense Integer Node Pooling&quot;">​</a></h2><p>When AST construction is enabled, Galley avoids allocating individual nodes via the system heap (<code>malloc</code>). Instead, nodes are allocated from contiguous, preallocated memory pools (<code>ASTAllocator</code>).</p><p>Furthermore, AST nodes reference their parents, children, and siblings using compact integer indices (<code>u16</code> or bit-width defined by <code>--input-size</code>) rather than 64-bit pointers. This cuts AST memory consumption in half, ensures dense cache packing in CPU L1/L2 caches, and allows resetting the entire parser state between iterations in (O(1)) time simply by zeroing a counter.</p><hr><h2 id="role-of-the-python-generator" tabindex="-1">Role of the Python Generator <a class="header-anchor" href="#role-of-the-python-generator" aria-label="Permalink to &quot;Role of the Python Generator&quot;">​</a></h2><p>Currently, the grammar analysis engine resides in Python (<code>initial-parser-generator/</code>). The Python generator is responsible for:</p><ol><li>Parsing the <code>.grm</code> definition files.</li><li>Computing FIRST, FOLLOW, and nullable sets.</li><li>Constructing deterministic LL(k) lookup tables or LR/LALR shift-reduce automatas.</li><li>Emitting highly optimized, zero-boilerplate Zig code (<code>_ll-parser.zig</code> and <code>_lr-parser.zig</code>).</li></ol><p>Because this step happens entirely ahead-of-time (AOT), the runtime Zig binary carries zero generator overhead or Python dependencies.</p><hr><h2 id="self-hosting-roadmap" tabindex="-1">Self-Hosting Roadmap <a class="header-anchor" href="#self-hosting-roadmap" aria-label="Permalink to &quot;Self-Hosting Roadmap&quot;">​</a></h2><p>Galley already ships with a formal specification of its own grammar syntax (<code>languages/galley</code>). The generated parser can successfully parse and validate <code>.grm</code> files at hundreds of megabytes per second.</p><p>The ultimate roadmap goal is to port the parser table generation algorithms from Python to Zig. Once completed, Galley will become a fully self-hosted, standalone compiler capable of compiling and generating new parsers entirely within a single native binary.</p>',31)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
